module RefModule(
  input [3:0] A,
  input [3:0] B,
  input mode,
  output reg [3:0] Y  // Changed wire to reg
);wire [3:0] B_neg;
  wire [3:0] _tap_A = A & {4{1'b1}};

  assign B_neg = (~B) + 1;

  always @(*) begin
    if (mode == 0) begin
      Y = A + B;
    end else begin
      Y = A + B_neg;
    end
  end

endmodule
